mapper.select:
SELECT session_id, state_key, item_index, state_data, created_at, updated_at
FROM session_chat
WHERE session_id = #{sessionId}
  AND state_key = #{stateKey}
  AND item_index = #{itemIndex}

SELECT session_id, state_key, item_index, state_data, created_at, updated_at
FROM session_chat
WHERE session_id = #{sessionId}
  AND state_key = #{stateKey}
ORDER BY item_index

SELECT MAX(item_index) as max_index
FROM session_chat
WHERE session_id = #{sessionId}
  AND state_key = #{stateKey}

mapper.delete:
DELETE FROM session_chat
WHERE session_id = #{sessionId}
  AND state_key = #{stateKey}
